var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후, 좋아. 이면카카오에 이 메탄올을 혼합하면…… 완벽해!","JPN":"ふふ、いいぞ。裏世界カカオにこのメタノールを混ぜると……完璧！","ENG":"Heh heh, good. Now mix the Counterside cacao with methanol... and it’s perfect!","TWN":"嘿嘿，在異界可可亞裡面加入甲醇，再攪一攪……完美！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"히익, 초콜릿에 그런 걸 넣어요? 역시 수상했어! 목적은 독살인 거죠?","JPN":"へっ、チョコレートにそんなものを入れるんですか？　やっぱり怪しい！　目的は毒殺ですか？","ENG":"You’re putting that thing into the chocolate? I knew something was fishy! You’re trying to poison someone, right?","TWN":"唔！在巧克力裡加入那種東西？果然很詭異！你是想下毒吧？！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아뇨, 제가 초콜릿을 드리려는 분은 신체기관이 조금 남달라서요.","JPN":"いいえ、私がチョコレートを差し上げたい方は身体器官が少し特別なんです。","ENG":"It’s not that. The person I’m giving this chocolate is a bit different from others.","TWN":"不是的，是因為我想送巧克力給他的對象，身體構造異於常人。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아니, 아무리 식성이 독특하다고 해도 이런 건 로봇이 아닌 이상…… ","JPN":"いや、いくら好みが変わっているとしても、こんなのはロボットじゃない以上…… ","ENG":"Well, I don’t think anyone will be able to eat it unless they are a robot...","TWN":"我不信！就算他的口味再怎麼特別，除非他是機器人否則…… "},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"설마 코핀 컴퍼니의 그 로봇 사장님한테 초콜릿을 선물하려는 건가요?","JPN":"まさかコフィンカンパニーのあのロボット社長にチョコレートをプレゼントするつもりですか？","ENG":"Did you make that chocolate for the robot CEO of the Coffin Company?","TWN":"難道你要送巧克力的對象，就是科芬公司的那個機器人老闆？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"흥, 당신이 선배님과 저의 정신적인 사랑을 이해할 거라고 기대하진 않아요.","JPN":"ふん、あなたが先輩と私のプラトニックな愛を理解してくれるとは期待していません。","ENG":"Hmpf, I don’t expect you to understand our platonic love.","TWN":"嗯，我不期待你理解我和老闆之間柏拉圖式的愛情。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"사랑……? 혹시 이 초콜렛으로 고백하시려고요?","JPN":"愛……？　もしかしてこのチョコレートで告白するつもりですか？","ENG":"Love? You’re planning to confess your love with this chocolate?","TWN":"愛情……？你是想用這個巧克力告白喔？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"맞아요. 그게 이상한가요?","JPN":"はい、おかしいですか？","ENG":"Yes. Something wrong?","TWN":"對啊，很奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"도와준 건 고맙지만, 우리의 사랑을 모욕할 셈이라면 나도 가만히 있지 않겠어요.","JPN":"助けてくれたのはありがたいけど、私たちの愛を侮辱するつもりなら許しません。","ENG":"I appreciate your help, but I’m not going to just sit back and take your insult, if that is your intention.","TWN":"我很感謝你的幫忙，但如果你敢嘲笑我們的愛情，我是不會放過你的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 전 대부분의 사랑을 지지하는 편이긴 한데 말이죠…….","JPN":"いいえ。私はほとんどの愛を支持する方ではありますけど……","ENG":"No, I do celebrate every type of love...","TWN":"放心吧，我通常是支持愛情的……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"제가 알고 있는 <color=#ffd34c>껄끄러운 비밀</color>을 고객님께서도 알아두는 편이 좋을 것 같아서요.","JPN":"私が知っている<color=#ffd34c>知られちゃまずい秘密</color>をお客様も知っておいたほうがいいと思いまして。","ENG":"But I think you should know this <color=#ffd34c>uncomfortable truth</color> first.","TWN":"只是有些<color=#ffd34c>你不知道的事</color>，你還是知道一下比較好。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};